using UnityEngine;
using UnityEngine.Purchasing;
using System;

public class PlayerStats : MonoBehaviour
{
    [Header("Core Stats (public)")]
    public int level = 1;
    public int maxHealth = 100;
    public int currentHealth = 100;

    [Header("Combat (public)")]
    public int baseDamage = 10;
    public float critChance = 0.1f;
    public float critMultiplier = 2.0f;

    [Header("Economy (public)")]
    public int softCurrency = 0;
    public int premiumCurrency = 0;

    [Header("Upgrade Levels (public)")]
    public int damageUpgradeLevel = 0;
    public int healthUpgradeLevel = 0;

    [Header("Upgrade Scaling (public)")]
    public int damagePerUpgrade = 2;
    public int healthPerUpgrade = 10;

    [Header("Runtime Derived (public)")]
    public int derivedDamage = 10;
    public int derivedMaxHealth = 100;

    public event Action<int, int> OnHealthChanged;
    public event Action<int, int> OnCurrencyChanged;

    private void Awake()
    {
        RecalculateDerivedStats();
        currentHealth = Mathf.Clamp(currentHealth, 0, derivedMaxHealth);
        RaiseHealthChanged();
        RaiseCurrencyChanged();
    }

    public void RecalculateDerivedStats()
    {
        derivedDamage = Mathf.Max(0, baseDamage + damageUpgradeLevel * damagePerUpgrade);
        derivedMaxHealth = Mathf.Max(1, maxHealth + healthUpgradeLevel * healthPerUpgrade);
        currentHealth = Mathf.Clamp(currentHealth, 0, derivedMaxHealth);
        RaiseHealthChanged();
    }

    public int RollDamage(System.Random rng = null)
    {
        int dmg = Mathf.Max(0, derivedDamage);
        float roll = (rng == null) ? UnityEngine.Random.value : (float)rng.NextDouble();
        bool isCrit = roll < Mathf.Clamp01(critChance);
        if (isCrit)
            dmg = Mathf.RoundToInt(dmg * Mathf.Max(1f, critMultiplier));
        return dmg;
    }

    public void ApplyDamage(int amount)
    {
        amount = Mathf.Max(0, amount);
        currentHealth = Mathf.Clamp(currentHealth - amount, 0, derivedMaxHealth);
        RaiseHealthChanged();
    }

    public void Heal(int amount)
    {
        amount = Mathf.Max(0, amount);
        currentHealth = Mathf.Clamp(currentHealth + amount, 0, derivedMaxHealth);
        RaiseHealthChanged();
    }

    public void AddSoftCurrency(int amount)
    {
        amount = Mathf.Max(0, amount);
        softCurrency = Mathf.Max(0, softCurrency + amount);
        RaiseCurrencyChanged();
    }

    public bool SpendSoftCurrency(int amount)
    {
        amount = Mathf.Max(0, amount);
        if (softCurrency < amount) return false;
        softCurrency -= amount;
        RaiseCurrencyChanged();
        return true;
    }

    public void AddPremiumCurrency(int amount)
    {
        amount = Mathf.Max(0, amount);
        premiumCurrency = Mathf.Max(0, premiumCurrency + amount);
        RaiseCurrencyChanged();
    }

    public bool SpendPremiumCurrency(int amount)
    {
        amount = Mathf.Max(0, amount);
        if (premiumCurrency < amount) return false;
        premiumCurrency -= amount;
        RaiseCurrencyChanged();
        return true;
    }

    private void RaiseHealthChanged()
    {
        OnHealthChanged?.Invoke(currentHealth, derivedMaxHealth);
    }

    private void RaiseCurrencyChanged()
    {
        OnCurrencyChanged?.Invoke(softCurrency, premiumCurrency);
    }
}

public enum ShopCurrencyType
{
    Soft,
    Premium
}

[Serializable]
public class ShopItemDefinition
{
    public string id;
    public string displayName;

    public ShopCurrencyType currencyType = ShopCurrencyType.Soft;

    [Header("Pricing")]
    public int basePrice = 10;
    public float priceGrowth = 1.15f;
    public int maxPurchases = -1;

    [Header("What it affects")]
    public ShopEffectType effectType = ShopEffectType.DamageUpgrade;
    public int effectAmount = 1;

    [Header("Optional: IAP Product Id (for premium top-ups)")]
    public string iapProductId;
}

public enum ShopEffectType
{
    DamageUpgrade,
    HealthUpgrade,
    HealFlat,
    AddSoftCurrency,
    AddPremiumCurrency
}

public class ShopSystem : MonoBehaviour
{
    [Header("References")]
    public PlayerStats player;

    [Header("Catalog")]
    public ShopItemDefinition[] items;

    [Header("Purchase State (public)")]
    public int[] purchaseCounts;

    public event Action<string> OnPurchaseSucceeded;
    public event Action<string> OnPurchaseFailed;

    private void Awake()
    {
        if (player == null) player = FindFirstObjectByType<PlayerStats>();
        if (items == null) items = Array.Empty<ShopItemDefinition>();
        purchaseCounts = new int[items.Length];
    }

    public int GetItemIndexById(string id)
    {
        for (int i = 0; i < items.Length; i++)
        {
            if (string.Equals(items[i].id, id, StringComparison.Ordinal))
                return i;
        }
        return -1;
    }

    public int GetPrice(int itemIndex)
    {
        if (itemIndex < 0 || itemIndex >= items.Length) return int.MaxValue;
        var def = items[itemIndex];
        int n = (purchaseCounts != null && itemIndex < purchaseCounts.Length) ? purchaseCounts[itemIndex] : 0;

        double price = def.basePrice * Math.Pow(Math.Max(1e-6, def.priceGrowth), Math.Max(0, n));
        long rounded = (long)Math.Round(price, MidpointRounding.AwayFromZero);
        if (rounded < 0) return int.MaxValue;
        if (rounded > int.MaxValue) return int.MaxValue;
        return (int)rounded;
    }

    public bool CanPurchase(int itemIndex)
    {
        if (player == null) return false;
        if (itemIndex < 0 || itemIndex >= items.Length) return false;

        var def = items[itemIndex];
        int n = purchaseCounts[itemIndex];

        if (def.maxPurchases >= 0 && n >= def.maxPurchases) return false;

        int price = GetPrice(itemIndex);
        if (def.currencyType == ShopCurrencyType.Soft)
            return player.softCurrency >= price;
        else
            return player.premiumCurrency >= price;
    }

    public bool TryPurchase(int itemIndex)
    {
        if (player == null)
        {
            OnPurchaseFailed?.Invoke("No player.");
            return false;
        }

        if (itemIndex < 0 || itemIndex >= items.Length)
        {
            OnPurchaseFailed?.Invoke("Invalid item index.");
            return false;
        }

        var def = items[itemIndex];
        int n = purchaseCounts[itemIndex];

        if (def.maxPurchases >= 0 && n >= def.maxPurchases)
        {
            OnPurchaseFailed?.Invoke("Max purchases reached.");
            return false;
        }

        int price = GetPrice(itemIndex);
        bool paid = def.currencyType == ShopCurrencyType.Soft
            ? player.SpendSoftCurrency(price)
            : player.SpendPremiumCurrency(price);

        if (!paid)
        {
            OnPurchaseFailed?.Invoke("Not enough currency.");
            return false;
        }

        ApplyEffect(def);

        purchaseCounts[itemIndex] = n + 1;

        if (def.effectType == ShopEffectType.DamageUpgrade || def.effectType == ShopEffectType.HealthUpgrade)
            player.RecalculateDerivedStats();

        OnPurchaseSucceeded?.Invoke(def.id);
        return true;
    }

    private void ApplyEffect(ShopItemDefinition def)
    {
        int amt = def.effectAmount;

        switch (def.effectType)
        {
            case ShopEffectType.DamageUpgrade:
                player.damageUpgradeLevel = Mathf.Max(0, player.damageUpgradeLevel + amt);
                break;

            case ShopEffectType.HealthUpgrade:
                player.healthUpgradeLevel = Mathf.Max(0, player.healthUpgradeLevel + amt);
                break;

            case ShopEffectType.HealFlat:
                player.Heal(amt);
                break;

            case ShopEffectType.AddSoftCurrency:
                player.AddSoftCurrency(amt);
                break;

            case ShopEffectType.AddPremiumCurrency:
                player.AddPremiumCurrency(amt);
                break;
        }
    }
}

public class CombatExample : MonoBehaviour
{
    public PlayerStats player;
    public int enemyHealth = 50;

    private void Awake()
    {
        if (player == null) player = FindFirstObjectByType<PlayerStats>();
        if (player != null) player.RecalculateDerivedStats();
    }

    public void PlayerAttackEnemy()
    {
        if (player == null) return;
        int dmg = player.RollDamage();
        enemyHealth = Mathf.Max(0, enemyHealth - dmg);
    }

    public void EnemyAttackPlayer(int enemyBaseDamage)
    {
        if (player == null) return;
        int dmg = Mathf.Max(0, enemyBaseDamage);
        player.ApplyDamage(dmg);
    }
}

public class SimpleIAPManager : MonoBehaviour, IStoreListener
{
    [Header("References")]
    public PlayerStats player;

    [Header("IAP Product Ids (configured in Unity IAP Catalog)")]
    public string premiumSmall = "premium_small";
    public string premiumMedium = "premium_medium";
    public string premiumLarge = "premium_large";

    [Header("Premium Currency Grants")]
    public int grantSmall = 100;
    public int grantMedium = 550;
    public int grantLarge = 1200;

    private static IStoreController storeController;
    private static IExtensionProvider extensionProvider;

    private void Awake()
    {
        if (player == null) player = FindFirstObjectByType<PlayerStats>();
    }

    private void Start()
    {
        if (storeController == null)
            InitializePurchasing();
    }

    public void InitializePurchasing()
    {
        if (IsInitialized()) return;

        var builder = ConfigurationBuilder.Instance(StandardPurchasingModule.Instance());
        if (!string.IsNullOrEmpty(premiumSmall)) builder.AddProduct(premiumSmall, ProductType.Consumable);
        if (!string.IsNullOrEmpty(premiumMedium)) builder.AddProduct(premiumMedium, ProductType.Consumable);
        if (!string.IsNullOrEmpty(premiumLarge)) builder.AddProduct(premiumLarge, ProductType.Consumable);

        UnityPurchasing.Initialize(this, builder);
    }

    public bool IsInitialized()
    {
        return storeController != null && extensionProvider != null;
    }

    public void BuyPremiumSmall() => BuyProductID(premiumSmall);
    public void BuyPremiumMedium() => BuyProductID(premiumMedium);
    public void BuyPremiumLarge() => BuyProductID(premiumLarge);

    public void BuyProductID(string productId)
    {
        if (!IsInitialized()) return;
        if (string.IsNullOrEmpty(productId)) return;

        Product product = storeController.products.WithID(productId);
        if (product != null && product.availableToPurchase)
            storeController.InitiatePurchase(product);
    }

    public void OnInitialized(IStoreController controller, IExtensionProvider extensions)
    {
        storeController = controller;
        extensionProvider = extensions;
    }

    public void OnInitializeFailed(InitializationFailureReason error)
    {
    }

#if UNITY_2022_2_OR_NEWER
    public void OnInitializeFailed(InitializationFailureReason error, string message)
    {
    }
#endif

    public PurchaseProcessingResult ProcessPurchase(PurchaseEventArgs args)
    {
        if (player == null) return PurchaseProcessingResult.Complete;

        string id = args.purchasedProduct.definition.id;

        if (string.Equals(id, premiumSmall, StringComparison.Ordinal))
            player.AddPremiumCurrency(grantSmall);
        else if (string.Equals(id, premiumMedium, StringComparison.Ordinal))
            player.AddPremiumCurrency(grantMedium);
        else if (string.Equals(id, premiumLarge, StringComparison.Ordinal))
            player.AddPremiumCurrency(grantLarge);

        return PurchaseProcessingResult.Complete;
    }

    public void OnPurchaseFailed(Product product, PurchaseFailureReason failureReason)
    {
    }
}